window.__QUIZ_DATA__=[{"id":"theory>Geography>2025 Paper 3>1>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the questions that follow.       In your answer booklet, draw a new outline of the section labelled QRST to a scale of 1:25,000","images":["data:image/jpeg;base64,","data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>1>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"In your ouline, insert and name  i. the two minor roads  ii. the main river and indicate its direction of flow with an arrow  iii. Garin Aba settlement","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"9","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>1>c","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : SETTLEMENT","question":"Outline three reasons for which KARLAHI is the most important settlement in the mapped area.","images":[],"marking_scheme":"(i)Transport Junction: KARLAHI is located at the intersection of major and minor roads, making it a central hub for transportation and communication within the mapped area.  (ii)Largest Settlement: It is visibly the largest settlement on the map, indicating a higher population density and more developed infrastructure compared to other settlements.  (iii)Presence of Institutions: KARLAHI hosts key facilities such as a school, a market, and possibly other services (as shown by symbols), which attract people from surrounding areas for education, trade, and services.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>1>d","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"d","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Using evidence from the map, identify three economic activities of the inhabitants in the mapped area","images":[],"marking_scheme":"(i)Farming and Agriculture: The map shows extensive farmland and scattered rural settlements, indicating that crop farming and possibly livestock rearing are primary occupations.  (ii)Trading/Commerce: The presence of markets (indicated by market symbols) shows that trading is a significant economic activity, with goods likely being exchanged within and outside the region.  (iii)Education: The presence of schools (school symbol) suggests that teaching and educational services contribute to the local economy, providing employment and attracting students from nearby villages.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>2>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The Table C below shows the value of imported commodities by a country in the years 2016 to 2020  Study and use it to answer the questions that follow  Table C  Year Value of imported commodities in millions Naira201680201712020182402019602020300    Using a vertical scale of 2cm to represent 40 million units of the value of imported commodities, construct a divergent bar graph to represent the data","images":["data:image/png;base64,"],"marking_scheme":"","marks":"13","difficulty":"3"},{"id":"theory>Geography>2025 Paper 3>2>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The Table C below shows the value of imported commodities by a country in the years 2016 to 2020  Study and use it to answer the questions that follow  Table C  Year Value of imported commodities in millions Naira201680201712020182402019602020300  State two disadvantages of divergent bar graphs","images":[],"marking_scheme":"-difficulty in comparison  -take more space  -requires many calculattion steps  -time consuming  -could be difficult to read or interprete","marks":"2","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>3>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Define the term lithosphere","images":[],"marking_scheme":"A lithosphere is the solid outer layer of the Earth, consisting of the crust and the uppermost part of the mantle. It is rigid and forms the Earth's landforms, such as mountains, valleys, and ocean basins.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>3>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"State three characteristics of the lithosphere","images":[],"marking_scheme":"(i) It is the outermost solid layer of the Earth.  (ii) It includes both the crust and the upper part of the mantle.  (iii) It is rigid and brittle in nature.  (iv) It is broken into tectonic plates that move over the asthenosphere.  (v) It contains both continental and oceanic crust.  (vi) It plays a role in the formation of landforms through geological processes like folding and faulting.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>3>c","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Outline five benefits of the lithosphere.","images":[],"marking_scheme":"(i) Source of minerals: The lithosphere contains valuable minerals like gold, iron, and copper used in industries.  (ii) Supports agriculture: It provides soil which is essential for growing crops and feeding livestock.  (iii) Habitat for living things: Humans, animals, and plants live on the land provided by the lithosphere.  (iv) Foundation for infrastructure: Buildings, roads, bridges, and other structures are built on the lithosphere.  (v) Source of fossil fuels: Resources like coal, oil, and natural gas used for energy come from the lithosphere.  (vi) Controls geological activities: Processes like earthquakes and volcanic eruptions originate in the lithosphere.  (vii) Supplies raw materials: Materials like clay, sand, and limestone used for making cement and glass come from it.  (viii) Supports scientific study: Rocks and fossils found in the lithosphere help scientists understand Earth's history.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>4>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is an ariesian well?","images":[],"marking_scheme":"An artesian well is a well drilled into a confined aquifer where water rises to the surface naturally due to pressure without the need for pumping.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>4>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Highlight four conditions that favour the formation of an artesian well.","images":[],"marking_scheme":"(i) Presence of a confined aquifer: This is a water-bearing layer of permeable rock or sediment that is sandwiched between two layers of impermeable rock, which traps the water under pressure.    (ii) Inclined aquifer structure: The aquifer must be tilted so that water can enter at a higher elevation and flow down to where the well is drilled, creating the necessary pressure.    (iii) Recharge area at a higher elevation: Water must be able to enter the aquifer at a location above the point where the well is drilled, increasing pressure due to gravity.    (iv) Impermeable layers above and below the aquifer: These layers prevent water from escaping, allowing pressure to build up within the confined aquifer.    (v) Adequate water supply: There must be consistent rainfall or surface water sources feeding into the recharge area to maintain pressure in the aquifer.    (vi) Proper drilling into the confined aquifer: The well must penetrate the pressurized aquifer correctly to allow the water to rise naturally to the surface without the need for pumping.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>4>c","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION~~ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Outline two usefulness of an artesian well.","images":[],"marking_scheme":"(i) Provides a reliable water supply: Artesian wells offer a consistent source of clean groundwater, especially in areas where surface water is scarce or unreliable.    (ii) Requires no pumping in some cases: Because of the natural pressure in the confined aquifer, water can flow to the surface without the need for mechanical pumps, saving energy and maintenance costs.    (iii) Supplies water for irrigation: Farmers can use artesian wells to irrigate crops, especially in dry regions where rainfall is insufficient.    (iv) Supports domestic and industrial use: The water from artesian wells can be used for drinking, cooking, cleaning, and even for industries that need large quantities of water.    (v) Less prone to contamination: Since the aquifer is confined between impermeable layers, the water is better protected from surface pollutants, making it safer for human use.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>5>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"State one difference between weather and climate","images":[],"marking_scheme":"(i) Weather refers to the atmospheric conditions of a place over a short period such as hours or days, while climate refers to the average atmospheric conditions of a place over a long period.  (ii) Weather can change rapidly within minutes or hours, while climate changes gradually over many years and remains relatively stable in the short term.  (iii) Weather is specific to a particular location and time, describing current conditions, while climate represents the general pattern of weather in a larger area over a long duration.  (iv) Weather involves short-term elements such as temperature, wind, rainfall, and humidity at a given moment, while climate involves long-term statistical data of these elements collected over decades.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>5>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of a diagram, describe the mode of formation of cyclonic rainfall","images":["data:image/jpeg;base64,"],"marking_scheme":"Cyclonic rainfall forms when a mass of warm, moist air is drawn into a low-pressure area and meets a colder air mass. The warm air is forced to rise over the denser cold air. As it rises, it cools, and the moisture it carries condenses to form clouds. Continued condensation leads to the development of heavy clouds, eventually resulting in precipitation in the form of rain. This process in cyclonic systems, where the convergence of contrasting air masses drives the upward movement of moist air, leads to rainfall.","marks":"7","difficulty":"3"},{"id":"theory>Geography>2025 Paper 3>5>c","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Highlight three benefits of cyclonic rainfall","images":[],"marking_scheme":"(i) Agricultural Support: Cyclonic rainfall supplies vital water needed for crop growth, especially in dry regions, thereby enhancing agricultural productivity and ensuring food security.  (ii) Water Resource Replenishment: The heavy rains help to recharge rivers, lakes, reservoirs, and underground aquifers, ensuring a steady supply of water for household, farming, and industrial use.  (iii) Improvement of Soil Fertility: Cyclonic rains can carry minerals and organic matter that enrich the soil, promoting better crop yields and supporting sustainable farming.  (iv) Electricity Generation: The increased water flow into dams due to cyclonic rainfall can be used in hydroelectric power stations to generate renewable energy, supporting economic development.  (v) Environmental Revitalization: Dry or desert areas benefit from cyclonic rains, which stimulate plant growth, restore greenery, and support ecosystems by providing water to wildlife.  (vi) Temperature Moderation: Cyclonic rainfall helps reduce high surface temperatures, creating cooler conditions and balancing heat in the atmosphere, which may prevent extreme heat events.  (vii) Air Purification: The downpour during cyclonic events helps to clean the atmosphere by removing dust, smoke, and other airborne pollutants, resulting in fresher, healthier air for breathing.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>6>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"What is a flood plain?","images":[],"marking_scheme":"A flood plain is a flat, low-lying area of land found along the sides of a river, which is periodically flooded when the river overflows its banks. It is formed mainly by deposition of sediments during flooding.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2025 Paper 3>6>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"With the aid of a diagram, describe the characteristics and mode of formation of a flood plain.","images":["data:image/png;base64,"],"marking_scheme":"CHARACTERISTICS OF A FLOOD PLAIN=  (i) Flood plains are usually broad, flat areas adjacent to a river channel.  (ii) The soil is often very fertile due to the regular deposition of nutrient-rich sediments during floods.  (iii) Flood plains experience periodic flooding when the river overflows its banks.  (iv) They often have meanders (curves or bends) in the river channel.  (v) The area supports lush vegetation because of the availability of water and fertile soil.  (vi) The surface is composed of fine alluvial deposits like silt, clay, and sand.  (vii) Raised banks or levees may form along the edges of the river channel from sediment deposits.    =MODE OF FORMATION OF A FLOOD PLAIN=  (i) When a river exceeds its bank capacity, water spills onto the surrounding land, causing flooding.  (ii) As the floodwater spreads out over the flat land, it slows down and deposits sediments carried from upstream.  (iii) Over many floods, layers of silt, clay, and fine sand accumulate, building up the flood plain.  (iv) The river's sideways erosion widens the valley floor, contributing to the flood plain's flatness.  (v) Coarser sediments settle first near the river banks during floods, forming natural levees.  (vi) The flood plain gradually extends as more sediments are deposited with each flood event.","marks":"12","difficulty":"3"},{"id":"theory>Geography>2025 Paper 3>7>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"List three processes of wind erosion.","images":[],"marking_scheme":"(i) Deflation: This is the process by which wind removes loose, fine particles such as sand and dust from the Earth's surface, often leaving behind a stony surface called desert pavement.  (ii) Abrasion: This occurs when wind-blown sand particles strike against rock surfaces, wearing them down through a sandblasting effect.  (iii) Attrition: This is the breaking down of rock particles carried by the wind as they collide with one another, resulting in smaller, smoother fragments.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>7>b>i","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight three:  similarities between a zeugen and a yardang.","images":[],"marking_scheme":"(i) Both are erosional landforms shaped primarily by wind action in arid environments.  (ii) Both are formed through the processes of deflation and abrasion.  (iii) Both exhibit elongated shapes aligned parallel to the prevailing wind direction.  (iv) Both result from differential erosion where softer rocks erode faster than harder rocks.  (v) Both are composed of alternating layers of hard and soft rock.  (vi) Both serve as indicators of the intensity and direction of past wind activity.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>7>b>ii","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Highlight three:  differences between a zeugen and a yardang.","images":[],"marking_scheme":"(i) A zeugen usually develops from horizontal rock layers, while a yardang forms from vertical or inclined rock strata.  (ii) A zeugen has a resistant cap rock over a softer base, while a yardang does not typically have a cap rock structure.  (iii) A zeugen is broader and more massive in appearance, while a yardang is narrower and more streamlined.  (iv) A zeugen forms mainly through undercutting and collapse, while a yardang forms through consistent abrasion by wind-blown particles.  (v) A zeugen often has a flat, table-like top, while a yardang has a sharp, ridge-like crest.  (vi) A zeugen may appear as isolated blocks or masses, while yardangs usually occur in groups forming ridges separated by grooves.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>8>a","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Define natural environment.","images":[],"marking_scheme":"A natural environment refers to all living and non-living things occurring naturally on Earth, including air, water, land, plants, animals, and other natural resources, not created or significantly altered by humans.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>8>b","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight four ways by which mankind destroys the natural environment","images":[],"marking_scheme":"Deforestation: The large-scale cutting down of trees for timber, agriculture, or urban development destroys habitats, reduces biodiversity, and contributes to climate change.  (ii) Pollution: The release of harmful substances into air, water, and soil from industries, vehicles, and households contaminates natural resources and endangers human and animal life.  (iii) Overgrazing: Excessive grazing by livestock on grasslands removes vegetation cover, leading to soil erosion, desertification, and loss of fertile land.  (iv) Mining Activities: The extraction of minerals from the earth disrupts ecosystems, causes land degradation, and contaminates water sources with toxic chemicals.  (v) Industrialization: The growth of industries often leads to the emission of greenhouse gases, disposal of hazardous wastes, and destruction of natural landscapes for infrastructure.  (vi) Urbanization: Expanding cities encroach upon forests, wetlands, and farmlands, leading to habitat loss and increased waste production.  (vii) Overfishing and Water Misuse: Unsustainable fishing and excessive use or diversion of water bodies for agriculture and human consumption disturb aquatic ecosystems and reduce water availability.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2025 Paper 3>8>c","subject":"Geography","year":"2025 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Outline two measures that can be adopted to control the destruction of the natural environment.","images":[],"marking_scheme":"(i) Afforestation and Reforestation: Planting new trees and restoring forests to replace those lost to deforestation helps preserve ecosystems and absorb carbon dioxide.  (ii) Environmental Education: Educating people about the importance of environmental protection encourages sustainable practices and responsible resource use.  (iii) Enforcing Environmental Laws: Implementing and enforcing laws that regulate pollution, waste disposal, and land use can help reduce environmental harm.  (iv) Promoting Renewable Energy: Shifting from fossil fuels to solar, wind, and other renewable energy sources reduces air pollution and greenhouse gas emissions.  (v) Waste Management and Recycling: Proper disposal, treatment, and recycling of waste materials reduce pollution and conserve natural\u00a0resources.","marks":"4","difficulty":"2"}];